from lxml import etree
from io import StringIO

from django.http import HttpResponse


def xpath_query(request):
    '''
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    '''
    # Get parameters from GET request
    xpath_value = request.GET.get('xpath', '')
    xml_value = request.GET.get('xml', '')

    # If no XML is provided, return an empty response
    if not xml_value:
        return HttpResponse("No XML provided", status=400)

    # Parse the XML
    try:
        root = etree.fromstring(xml_value.encode('utf-8'))
    except etree.XMLSyntaxError:
        return HttpResponse("Invalid XML", status=400)

    # If no xpath_value is provided, return an error
    if not xpath_value:
        return HttpResponse("No xpath provided", status=400)

    # Safely construct the XPath query by escaping single quotes in the xpath_value
    # to prevent XPath injection (though this is minimal protection)
    escaped_xpath_value = xpath_value.replace("'", "&apos;")

    # Construct the XPath query
    xpath_query_str = f"/tag[@id='{escaped_xpath_value}']"

    # Execute the XPath query
    try:
        results = root.xpath(xpath_query_str)
    except Exception:
        return HttpResponse("Invalid XPath query", status=400)

    # Return the results as a string representation
    result_str = ", ".join([etree.tostring(elem, encoding='unicode') for elem in results])
    return HttpResponse(result_str, content_type="text/plain")
